class Solution:
    def equationsPossible(self, equations):
        from itertools import product
        eqs = [(e[0], e[3]) for e in equations if e[1] == '=']
        neqs = [(e[0], e[3]) for e in equations if e[1] == '!']
        adj = {chr(c): set() for c in range(ord('a'), ord('z') + 1)}
        for x, y in eqs:
            adj[x].add(y)
            adj[y].add(x)
        comp = {}
        cid = 0
        for start in adj:
            if start in comp:
                continue
            stack = [start]
            comp[start] = cid
            while stack:
                u = stack.pop()
                for v in adj[u]:
                    if v not in comp:
                        comp[v] = cid
                        stack.append(v)
            cid += 1
        for x, y in neqs:
            if comp[x] == comp[y]:
                return False
        return True

