class Solution:
    def equationsPossible(self, equations):
        parent = list(range(26))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            parent[find(a)] = find(b)
        for e in equations:
            if e[1] == '=':
                union(ord(e[0]) - 97, ord(e[3]) - 97)
        for e in equations:
            if e[1] == '!':
                if find(ord(e[0]) - 97) == find(ord(e[3]) - 97):
                    return False
        return True

