var equationsPossible = function(equations) {
    const parent = Array.from({length: 26}, (_, i) => i);
    const find = (x) => {
        while (parent[x] !== x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    };
    const union = (a, b) => { parent[find(a)] = find(b); };
    for (const e of equations) {
        if (e[1] === '=') union(e.charCodeAt(0) - 97, e.charCodeAt(3) - 97);
    }
    for (const e of equations) {
        if (e[1] === '!') {
            if (find(e.charCodeAt(0) - 97) === find(e.charCodeAt(3) - 97)) return false;
        }
    }
    return true;
};
